import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { apiClient, authService } from "@/App";
import {
  Bell, CreditCard, Calendar, Download, Award,
  TrendingUp, User, BookOpen, MessageSquare
} from "lucide-react";
import jsPDF from "jspdf";
import { toast } from "sonner";

/* -------------------- GRADING -------------------- */
const gradeColor = (g) => {
  if (g === "EE") return "bg-emerald-500/10 text-emerald-400 border-emerald-500/20";
  if (g === "ME") return "bg-blue-500/10 text-blue-400 border-blue-500/20";
  if (g === "AE") return "bg-yellow-500/10 text-yellow-400 border-yellow-500/20";
  return "bg-red-500/10 text-red-400 border-red-500/20";
};

const StudentPortal = () => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  const user = authService.getUser();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const res = await apiClient.get("/portal/my-data");
      setData(res.data || null);
    } catch (err) {
      console.error("Portal load error:", err);
      toast.error("Failed to load student data");
    } finally {
      setLoading(false);
    }
  };

  /* ---------------- SAFE EXTRACTION ---------------- */
  const student = data?.student || null;
  const results = data?.results || [];
  const payments = data?.payments || [];
  const announcements = data?.announcements || [];
  const attendance = data?.attendance || [];
  const attStats = data?.attendance_stats || {};

  const totalFees = data?.total_fees || 0;
  const totalPaid = data?.total_paid || 0;
  const balance = data?.fee_balance || 0;

  /* ---------------- PDF: FEES ---------------- */
  const generateFeeStatement = () => {
    const doc = new jsPDF();

    doc.setFontSize(18);
    doc.text("School Fee Statement", 20, 20);

    doc.setFontSize(12);
    doc.text(`Student: ${student?.full_name || "N/A"}`, 20, 35);
    doc.text(`Admission: ${student?.admission_number || "N/A"}`, 20, 45);
    doc.text(`Class: ${student?.class_name || "N/A"}`, 20, 55);

    doc.text(`Total Fees: KES ${totalFees.toLocaleString()}`, 20, 70);
    doc.text(`Total Paid: KES ${totalPaid.toLocaleString()}`, 20, 80);
    doc.text(`Balance: KES ${balance.toLocaleString()}`, 20, 90);

    let y = 110;
    doc.text("Payments:", 20, y);
    y += 10;

    payments.forEach((p, i) => {
      if (y > 270) {
        doc.addPage();
        y = 20;
      }

      doc.text(
        `${i + 1}. KES ${p.amount} - ${p.payment_method} - ${new Date(
          p.created_at
        ).toLocaleDateString()} (${p.status})`,
        20,
        y
      );

      y += 7;
    });

    doc.save(`fee-statement-${Date.now()}.pdf`);
    toast.success("Downloaded fee statement");
  };

  /* ---------------- PDF: RESULTS ---------------- */
  const generateReportCard = () => {
    const doc = new jsPDF();

    doc.setFontSize(18);
    doc.text("Student Report Card", 20, 20);

    doc.setFontSize(12);
    doc.text(`Name: ${student?.full_name || "N/A"}`, 20, 35);
    doc.text(`Class: ${student?.class_name || "N/A"}`, 20, 45);

    let y = 65;
    doc.text("Results:", 20, y);
    y += 10;

    results.forEach((r) => {
      if (y > 270) {
        doc.addPage();
        y = 20;
      }

      doc.text(
        `${r.subject}: ${r.marks}/${r.max_marks} - ${r.grade}`,
        20,
        y
      );

      y += 7;
    });

    doc.save(`report-card-${Date.now()}.pdf`);
    toast.success("Report card downloaded");
  };

  /* ---------------- LOADING ---------------- */
  if (loading) {
    return (
      <div className="text-slate-400 p-6">
        Loading student portal...
      </div>
    );
  }

  return (
    <div className="space-y-6" data-testid="student-portal">

      {/* HEADER */}
      <div className="bg-gradient-to-r from-blue-600/20 to-indigo-600/20 border border-blue-500/20 rounded-2xl p-8">

        <h2 className="text-3xl font-bold text-white">
          Student Portal
        </h2>

        <p className="text-slate-400 mt-1">
          Welcome, {user?.full_name || "Student"}
        </p>

        {student && (
          <div className="flex gap-2 mt-4 flex-wrap">

            <Badge className="bg-white/5 text-white">
              <User className="w-4 h-4 mr-1" />
              {student.full_name}
            </Badge>

            <Badge className="bg-white/5 text-white">
              <BookOpen className="w-4 h-4 mr-1" />
              {student.class_name || "N/A"}
            </Badge>

            <Badge className="bg-white/5 text-white">
              {student.admission_number}
            </Badge>

          </div>
        )}

      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader><CardTitle className="text-slate-400 text-sm">Fee Balance</CardTitle></CardHeader>
          <CardContent className="text-white text-xl">
            KES {balance.toLocaleString()}
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader><CardTitle className="text-slate-400 text-sm">Attendance</CardTitle></CardHeader>
          <CardContent className="text-white text-xl">
            {attStats.rate || 0}%
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader><CardTitle className="text-slate-400 text-sm">Subjects</CardTitle></CardHeader>
          <CardContent className="text-white text-xl">
            {results.length}
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader><CardTitle className="text-slate-400 text-sm">Announcements</CardTitle></CardHeader>
          <CardContent className="text-white text-xl">
            {announcements.length}
          </CardContent>
        </Card>

      </div>

      {/* TABS */}
      <Tabs defaultValue="results">

        <TabsList className="bg-[#0F1A2A] border border-[#1E293B]">
          <TabsTrigger value="results">Results</TabsTrigger>
          <TabsTrigger value="fees">Fees</TabsTrigger>
          <TabsTrigger value="attendance">Attendance</TabsTrigger>
          <TabsTrigger value="announcements">Announcements</TabsTrigger>
        </TabsList>

        {/* RESULTS */}
        <TabsContent value="results">
          <Card className="bg-[#1A2332] border-[#1E293B]">
            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-emerald-400" />
                Academic Results
              </CardTitle>

              <Button onClick={generateReportCard} className="mt-3">
                <Download className="w-4 h-4 mr-2" />
                Download Report
              </Button>
            </CardHeader>

            <CardContent>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Subject</TableHead>
                    <TableHead>Marks</TableHead>
                    <TableHead>Grade</TableHead>
                    <TableHead>Comments</TableHead>
                  </TableRow>
                </TableHeader>

                <TableBody>
                  {results.map((r) => (
                    <TableRow key={r.id} data-testid="result-row">

                      <TableCell className="text-white">
                        {r.subject}
                      </TableCell>

                      <TableCell className="text-slate-300">
                        {r.marks}/{r.max_marks}
                      </TableCell>

                      <TableCell>
                        <Badge className={gradeColor(r.grade)}>
                          {r.grade}
                        </Badge>
                      </TableCell>

                      <TableCell className="text-slate-400">
                        {r.teacher_comments || "-"}
                      </TableCell>

                    </TableRow>
                  ))}
                </TableBody>

              </Table>
            </CardContent>

          </Card>
        </TabsContent>

        {/* FEES */}
        <TabsContent value="fees">
          <Card className="bg-[#1A2332] border-[#1E293B]">

            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <CreditCard className="w-4 h-4 text-green-400" />
                Fee Records
              </CardTitle>

              <Button onClick={generateFeeStatement}>
                <Download className="w-4 h-4 mr-2" />
                Statement
              </Button>
            </CardHeader>

            <CardContent>

              {payments.length === 0 ? (
                <p className="text-slate-400">No payments found</p>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Date</TableHead>
                      <TableHead>Amount</TableHead>
                      <TableHead>Method</TableHead>
                      <TableHead>Status</TableHead>
                    </TableRow>
                  </TableHeader>

                  <TableBody>
                    {payments.map((p) => (
                      <TableRow key={p.id} data-testid="payment-row">

                        <TableCell>
                          {new Date(p.created_at).toLocaleDateString()}
                        </TableCell>

                        <TableCell className="text-green-400">
                          KES {p.amount}
                        </TableCell>

                        <TableCell>
                          {p.payment_method}
                        </TableCell>

                        <TableCell>
                          <Badge>
                            {p.status}
                          </Badge>
                        </TableCell>

                      </TableRow>
                    ))}
                  </TableBody>

                </Table>
              )}

            </CardContent>

          </Card>
        </TabsContent>

        {/* ATTENDANCE */}
        <TabsContent value="attendance">
          <Card className="bg-[#1A2332] border-[#1E293B]">
            <CardContent className="p-6 text-slate-400">
              Attendance records loaded from backend
            </CardContent>
          </Card>
        </TabsContent>

        {/* ANNOUNCEMENTS */}
        <TabsContent value="announcements">

          <Card className="bg-[#1A2332] border-[#1E293B]">

            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <Bell className="w-4 h-4 text-blue-400" />
                Announcements
              </CardTitle>
            </CardHeader>

            <CardContent>

              {announcements.length === 0 ? (
                <p className="text-slate-400">No announcements</p>
              ) : (
                announcements.map((a) => (
                  <div key={a.id} className="p-3 border border-[#1E293B] rounded mb-2">

                    <div className="flex justify-between">
                      <p className="text-white font-medium">{a.title}</p>
                      <Badge>{a.priority}</Badge>
                    </div>

                    <p className="text-slate-400 text-sm mt-1">
                      {a.content}
                    </p>

                  </div>
                ))
              )}

            </CardContent>

          </Card>

        </TabsContent>

      </Tabs>

    </div>
  );
};

export default StudentPortal;
